#ifndef FUSED_ADD_RMSNORM_H
#define FUSED_ADD_RMSNORM_H

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <stdint.h>

// Configuration constants
constexpr int HIDDEN_SIZE = 2048;
constexpr int BLOCK_SIZE = 256;
constexpr float EPS = 1e-6f;

/**
 * CUDA Kernel for Fused Add + RMSNorm
 * 
 * Optimized for A800 (Ampere) architecture:
 * - Uses BF16 for IO, FP32 for computation
 * - Shared memory for reduction with bank conflict optimization
 * - Coalesced global memory access
 * - Warp-level reduction primitives
 * - Reduced synchronization points
 * 
 * @param hidden_states Input hidden states [batch_size, HIDDEN_SIZE]
 * @param residual Residual input [batch_size, HIDDEN_SIZE]
 * @param weight Weight parameters [HIDDEN_SIZE]
 * @param output Output tensor [batch_size, HIDDEN_SIZE]
 * @param batch_size Number of sequences in the batch
 */
__global__ void fused_add_rmsnorm_kernel(
    const __nv_bfloat16* __restrict__ hidden_states,
    const __nv_bfloat16* __restrict__ residual,
    const __nv_bfloat16* __restrict__ weight,
    __nv_bfloat16* __restrict__ output,
    int batch_size
);

/**
 * Host wrapper function to launch the kernel
 * 
 * @param hidden_states Input hidden states [batch_size, HIDDEN_SIZE]
 * @param residual Residual input [batch_size, HIDDEN_SIZE]
 * @param weight Weight parameters [HIDDEN_SIZE]
 * @param output Output tensor [batch_size, HIDDEN_SIZE]
 * @param batch_size Number of sequences in the batch
 */
void launch_fused_add_rmsnorm(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* residual,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size
);

#endif // FUSED_ADD_RMSNORM_H

#include "kernel.h"
#include <device_launch_parameters.h>
#include <math_constants.h>

// Warp size for A800
constexpr int WARP_SIZE = 32;
constexpr int WARPS_PER_BLOCK = BLOCK_SIZE / WARP_SIZE;

__global__ void fused_add_rmsnorm_kernel(
    const __nv_bfloat16* __restrict__ hidden_states,
    const __nv_bfloat16* __restrict__ residual,
    const __nv_bfloat16* __restrict__ weight,
    __nv_bfloat16* __restrict__ output,
    int batch_size
) {
    // Shared memory for intermediate x values (FP32)
    // 2048 floats = 8KB, well within shared memory limits
    __shared__ float s_x[HIDDEN_SIZE];

    // Shared memory for warp partial sums with padding to avoid bank conflicts
    __shared__ float s_warp_sums[WARPS_PER_BLOCK + 1]; 

    int row_idx = blockIdx.x;
    if (row_idx >= batch_size) return;

    int tid = threadIdx.x;
    int lane_id = tid % WARP_SIZE;
    int warp_id = tid / WARP_SIZE;

    // Calculate row offsets
    const __nv_bfloat16* row_hidden = hidden_states + row_idx * HIDDEN_SIZE;
    const __nv_bfloat16* row_residual = residual + row_idx * HIDDEN_SIZE;
    __nv_bfloat16* row_output = output + row_idx * HIDDEN_SIZE;

    // Phase 1: Load, Add, Compute Sum of Squares
    float sum_sq = 0.0f;

    // Each thread processes HIDDEN_SIZE / BLOCK_SIZE = 8 elements
    // Unroll loop for better performance
    #pragma unroll 8
    for (int i = tid; i < HIDDEN_SIZE; i += BLOCK_SIZE) {
        // Load hidden and residual (coalesced access)
        __nv_bfloat16 h = row_hidden[i];
        __nv_bfloat16 r = row_residual[i];

        // Convert to FP32 and Add
        float x_val = __bfloat162float(h) + __bfloat162float(r);

        // Store to shared memory for later use
        s_x[i] = x_val;

        // Accumulate sum of squares
        sum_sq += x_val * x_val;
    }

    __syncthreads();

    // Phase 2: Block-wide Reduction for Sum of Squares
    // Step 2a: Warp-level reduction using shuffle operations
    float warp_sum = sum_sq;
    #pragma unroll
    for (int offset = WARP_SIZE / 2; offset > 0; offset /= 2) {
        warp_sum += __shfl_down_sync(0xffffffff, warp_sum, offset);
    }

    // Step 2b: Store warp result to shared memory (only lane 0 writes)
    if (lane_id == 0) {
        s_warp_sums[warp_id] = warp_sum;
    }
    __syncthreads();

    // Step 2c: Reduce warp results (only warp 0 participates)
    // Use padding to avoid bank conflicts
    if (warp_id == 0) {
        float total_sum_sq = 0.0f;
        #pragma unroll
        for (int i = 0; i < WARPS_PER_BLOCK; i++) {
            total_sum_sq += s_warp_sums[i];
        }
        s_warp_sums[0] = total_sum_sq;
    }
    __syncthreads();

    // All threads read the final sum from shared memory
    float final_sum_sq = s_warp_sums[0];
    float variance = final_sum_sq / HIDDEN_SIZE;
    float inv_rms = rsqrtf(variance + EPS);

    // Phase 3: Normalize and Apply Weight
    // Each thread processes 8 elements
    #pragma unroll 8
    for (int i = tid; i < HIDDEN_SIZE; i += BLOCK_SIZE) {
        float x_val = s_x[i];

        // Load weight from global memory (coalesced)
        // Weight is BF16, convert to FP32
        float w_val = __bfloat162float(weight[i]);

        // Compute output: (x * inv_rms) * weight
        float y_val = x_val * inv_rms * w_val;

        // Store to global memory (BF16)
        row_output[i] = __float2bfloat16(y_val);
    }
}

// Host wrapper function to launch the kernel
void launch_fused_add_rmsnorm(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* residual,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size
) {
    // Kernel Launch Configuration
    // 1 Block per row in batch
    int blocks = batch_size;
    int threads = BLOCK_SIZE;

    // Launch Kernel
    fused_add_rmsnorm_kernel<<<blocks, threads>>>(
        hidden_states,
        residual,
        weight,
        output,
        batch_size
    );
}

#include <torch/extension.h>
#include "kernel.h"
#include <cuda_runtime.h>
#include <vector>
#include <stdexcept>
#include <ATen/cuda/CUDAContext.h>
#include <ATen/ATen.h>

// Error checking macro
#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            throw std::runtime_error(std::string("CUDA error: ") + cudaGetErrorString(err)); \
        } \
    } while(0)

torch::Tensor run(
    torch::Tensor hidden_states,
    torch::Tensor residual,
    torch::Tensor weight,
    torch::Tensor output
) {
    // Input Validation - Device Check
    if (!hidden_states.is_cuda()) {
        throw std::runtime_error("hidden_states must be on CUDA device");
    }
    if (!residual.is_cuda()) {
        throw std::runtime_error("residual must be on CUDA device");
    }
    if (!weight.is_cuda()) {
        throw std::runtime_error("weight must be on CUDA device");
    }
    if (!output.is_cuda()) {
        throw std::runtime_error("output must be on CUDA device");
    }

    // Input Validation - Dtype Check
    if (hidden_states.scalar_type() != at::ScalarType::BFloat16) {
        throw std::runtime_error("hidden_states must be BF16");
    }
    if (residual.scalar_type() != at::ScalarType::BFloat16) {
        throw std::runtime_error("residual must be BF16");
    }
    if (weight.scalar_type() != at::ScalarType::BFloat16) {
        throw std::runtime_error("weight must be BF16");
    }
    if (output.scalar_type() != at::ScalarType::BFloat16) {
        throw std::runtime_error("output must be BF16");
    }

    // Input Validation - Shape Check
    auto batch_size = hidden_states.size(0);
    auto hidden_size = hidden_states.size(1);

    if (hidden_size != HIDDEN_SIZE) {
        throw std::runtime_error("Hidden size must be 2048, got " + std::to_string(hidden_size));
    }
    if (residual.size(0) != batch_size || residual.size(1) != hidden_size) {
        throw std::runtime_error("Residual shape mismatch");
    }
    if (weight.size(0) != hidden_size) {
        throw std::runtime_error("Weight shape mismatch");
    }
    if (output.size(0) != batch_size || output.size(1) != hidden_size) {
        throw std::runtime_error("Output shape mismatch");
    }

    // Launch kernel via wrapper function
    // Use at::BFloat16 for data_ptr in host code, which maps to __nv_bfloat16 on device
    launch_fused_add_rmsnorm(
        reinterpret_cast<const __nv_bfloat16*>(hidden_states.data_ptr<at::BFloat16>()),
        reinterpret_cast<const __nv_bfloat16*>(residual.data_ptr<at::BFloat16>()),
        reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr<at::BFloat16>()),
        reinterpret_cast<__nv_bfloat16*>(output.data_ptr<at::BFloat16>()),
        batch_size
    );

    // Check for kernel launch errors
    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaDeviceSynchronize());

    return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Fused Add + RMSNorm Kernel",
          py::arg("hidden_states"),
          py::arg("residual"),
          py::arg("weight"),
          py::arg("output"));
}
